  \begin {array}{l}
  \eta _{ s } : { \eta _{ J } ;s }  \sim _{ A \to  I } { \eta _{ I } }   \\ 
  \eta _{ s } a : \equiv   \mathsf { refl } 
\end {array}

  \begin {aligned}
 s { \mathopen {} \left ( \eta _{ J } a \right ) \mathclose {}}  &  \equiv  s { \mathopen {} \left ( r { \mathopen {} \left ( \eta _{ I } a \right ) \mathclose {}} \right ) \mathclose {}} 
  \\ 
                     &  \equiv  p _{ I } { \mathopen {} \left ( \eta _{ I } a \right ) \mathclose {}} 
  \\ 
                     &  \equiv   \eta _{ I } a
\end {aligned}

  \begin {aligned}
  \eta _{ s;r } a  \bullet   \rho { \mathopen {} \left ( \eta _{ J } a \right ) \mathclose {}} 
  &  \equiv 
  { \mathopen {} \left ( \mathsf { ap } _{ r } { \mathopen {} \left ( \eta _{ s } a \right ) \mathclose {}}   \bullet   \eta _{ r } a \right ) \mathclose {}}   \bullet   \rho { \mathopen {} \left ( r { \mathopen {} \left ( \eta _{ I } a \right ) \mathclose {}} \right ) \mathclose {}} 
  \\ 
  &  \equiv 
  { \mathopen {} \left ( \mathsf { ap } _{ r } \mathsf { refl }   \bullet   \mathsf { refl } \right ) \mathclose {}}   \bullet   \rho { \mathopen {} \left ( r { \mathopen {} \left ( \eta _{ I } a \right ) \mathclose {}} \right ) \mathclose {}} 
  \\ 
  &  \equiv 
  { \mathopen {} \left ( \mathsf { refl } \bullet \mathsf { refl } \right ) \mathclose {}}   \bullet   \rho { \mathopen {} \left ( r { \mathopen {} \left ( \eta _{ I } a \right ) \mathclose {}} \right ) \mathclose {}} 
  \\ 
  &  \equiv 
  \mathsf { refl } \bullet   \rho { \mathopen {} \left ( r { \mathopen {} \left ( \eta _{ I } a \right ) \mathclose {}} \right ) \mathclose {}} 
  \\ 
  & =
  \rho { \mathopen {} \left ( r { \mathopen {} \left ( \eta _{ I } a \right ) \mathclose {}} \right ) \mathclose {}} 
\end {aligned}

  \begin {aligned}
  \rho { \mathopen {} \left ( r { \mathopen {} \left ( \eta _{ I } a \right ) \mathclose {}} \right ) \mathclose {}} 
  & =  \mathsf { ap } _{ r } { \mathopen {} \left ( \vartheta _{ \eta _{ I } a } p _{ I } \right ) \mathclose {}} 
  \\ 
  &  \equiv   \mathsf { ap } _{ r }   { \mathopen {} \left ( \eta _{ p _{ I } } a \right ) \mathclose {}} 
  \\ 
  &  \equiv   \mathsf { ap } _{ r } \mathsf { refl } 
  \\ 
  &  \equiv   \mathsf { refl } 
\end {aligned}

